      "export": "Files"
    },
    {
      "name": "code_chunks",
      "path": "dist/methods/src/tables/codeChunks.ts",
      "export": "CodeChunks"
    },
    {
      "name": "generated_docs",
      "path": "dist/methods/src/tables/generatedDocs.ts",
      "export": "GeneratedDocs"
    }
  ],
