    // uploadDataSourceDocument handles chunking, embedding, and indexing.
    // Pass raw text (not a URL) and it creates a .txt document automatically.
    // Polls until processing is done — immediately queryable after this resolves.
    await mindstudio.uploadDataSourceDocument({
      dataSourceId,
      file: content,    // raw text string → creates a .txt document
      fileName,
    });
  } catch (err) {
    if (err instanceof MindStudioError) {
      console.error(`Ingestion failed [${err.code}] ${err.status}:`, err.message);
      throw err;
    }
    throw err;
  }
}

export async function retrieve(
  dataSourceId: string,
  query: string,
  maxResults = 5,
): Promise<string> {
