+  // 5. Persist in batches.
+  for (let i = 0; i < rows.length; i += INSERT_BATCH_SIZE) {
+    const slice = rows.slice(i, i + INSERT_BATCH_SIZE);
+    const mutations = slice.map((r) => CodeChunks.push(r));
+    await db.batch(...mutations);
+  }
