+      `[chunkAndEmbedFile] fileId=${fileId} persisted ${rows.length} chunks, ${failed} failed to embed`,
+    );
+  } else {
+    console.log(
+      `[chunkAndEmbedFile] fileId=${fileId} persisted ${rows.length} chunks`,
+    );
+  }
+
+  return { chunkCount: rows.length, failedChunkCount: failed };
